/**
 * Generate user test data based on pattern
 *
 * @param pattern - The test data pattern to generate
 * @param overrides - Optional field overrides
 * @returns Generated test data
 *
 * @example
 * ```typescript
 * // Generate complete test data
 * const data = generateUserTestData('complete');
 *
 * // Generate unique test data with overrides
 * const customData = generateUserTestData('unique', {
 *   is_active: false,
 * });
 * ```
 */
export function generateUserTestData(
  pattern: TestDataPattern = 'complete',
  overrides: Partial<UserCreateRequest> = {}
): UserCreateRequest {
  let baseData: UserCreateRequest;

  switch (pattern) {
    case 'minimal':
      baseData = { ...minimalUserFixture };
      break;

    case 'complete':
      baseData = { ...completeUserFixture };
      break;

    case 'invalid':
      // Return invalid data (caller should handle validation failure)
      baseData = { ...invalidUserFixture } as UserCreateRequest;
      break;

    case 'unique':
      // Generate fresh unique values for each call
      baseData = {
        ...uniqueUserFixture,
      };
      break;

    default:
      baseData = { ...completeUserFixture };
  }

  return { ...baseData, ...overrides };
}

